        heap.sort((a, b) => {
            if (a.times === b.times) {
                return a.sentence.localeCompare(b.sentence);
            }
            return b.times - a.times;
        });

        const res = [];
        for (let i = 0; i < 3 && i < heap.length; ++i) {
            res.push(heap[i].sentence);
        }
        return res;
    }
